import React, { useCallback } from 'react';
import {
  NavLink,
  useLocation,
  useHistory,
  useRouteMatch,
} from 'react-router-dom';
import classNames from 'classnames';
import './Categories.scss';

export const Categories = () => {
  const categoryListFirst = ['Sports', 'World', 'Covid', 'Business'];
  const categoryListSecond = ['Politics', 'Science', 'Religion', 'Heals'];
  const location = useLocation();
  const history = useHistory();
  const searchParams = new URLSearchParams(location.search) || '';
  const match = useRouteMatch();
  const category = searchParams.get('category');
  // console.log(location.pathname);
  const { pathname } = location;
  const handleClick = useCallback((item) => {
    searchParams.set('category', `${item}`);
    history.push(`?${searchParams}`);
  }, [searchParams, history]);
  // console.log(pathname, history);
  // console.log(location.pathname);

  return (
    <div className="Categories">
      <ul className="Categories-categoryListFirst list">
        {categoryListFirst.map(item => (
          <li className="Categories-Item" key={item}>
            <button
              type="button"
              className={classNames('Categories-Link', {
                is_active: item === category,
              })}
              onClick={handleClick}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>

      <ul className="Categories-categoryListSecond list">
        {categoryListSecond.map(item => (
          <li className="Categories-Item" key={item}>
            <NavLink
              to={`${pathname}/${item}`}
              className="Categories-Link"
            >
              {item}
            </NavLink>
          </li>
        ))}
      </ul>
    </div>
  );
};
